+  <script>
+    document.addEventListener("DOMContentLoaded", function() {
+      var searchBtn = document.getElementById("search-icon-btn");
+      var searchOverlay = document.getElementById("search-overlay");
+      var closeSearch = document.getElementById("close-search");
+      var searchInput = document.getElementById("overlay-search-input");
+
+      if (searchBtn && searchOverlay) {
+        searchBtn.addEventListener("click", function(e) {
+          e.preventDefault();
+          searchOverlay.style.display = "flex";
+          setTimeout(function() { searchInput.focus(); }, 100);
+        });
+
+        closeSearch.addEventListener("click", function() {
+          searchOverlay.style.display = "none";
+        });
+
+        searchOverlay.addEventListener("click", function(e) {
+          if (e.target === searchOverlay) {
+            searchOverlay.style.display = "none";
+          }
+        });
+
+        document.addEventListener("keydown", function(e) {
+          if ((e.ctrlKey || e.metaKey) && e.key === "k") {
+            e.preventDefault();
+            searchOverlay.style.display = "flex";
+            setTimeout(function() { searchInput.focus(); }, 100);
+          } else if (e.key === "Escape" && searchOverlay.style.display === "flex") {
+            e.preventDefault();
+            searchOverlay.style.display = "none";
+          }
+          else if (e.key === "Enter" && searchOverlay.style.display === "flex") {
+            var activeElement = document.activeElement;
+            if (activeElement === searchInput) {
+              e.preventDefault();
+              activeElement.form.submit();
+            }
+          }
+        });
+      }
+    });
+  </script>
